import os
import sys
import subprocess


def run(cmd, env=None):
    print("+ " + " ".join(cmd), flush=True)
    subprocess.check_call(cmd, env=env)


def main():
    requirements_file = os.environ.get("REQUIREMENTS_FILE", "requirements.txt")

    if not os.path.exists(requirements_file):
        print(f"ERROR: Requirements file not found: {requirements_file}", file=sys.stderr)
        sys.exit(2)

    python = sys.executable
    pip_cmd = [python, "-m", "pip"]

    # Keep output manageable in CI unless overridden
    quiet = os.environ.get("PIP_QUIET", "1") not in ("0", "false", "False", "no", "NO")
    verbosity_flags = ["-q"] if quiet else []

    # Speed-focused flags
    # Disable pip's version check, avoid caches if requested
    env = os.environ.copy()
    env.setdefault("PIP_DISABLE_PIP_VERSION_CHECK", "1")
    env.setdefault("PYTHONDONTWRITEBYTECODE", "1")

    no_cache = os.environ.get("PIP_NO_CACHE_DIR", "0") in ("1", "true", "True", "yes", "YES")
    extra_install_args = []
    if no_cache:
        extra_install_args.append("--no-cache-dir")

    # Upgrade pip tooling first (optional but helpful)
    if os.environ.get("UPGRADE_PIP_TOOLS", "1") in ("1", "true", "True", "yes", "YES"):
        run(
            pip_cmd
            + ["install"]
            + verbosity_flags
            + extra_install_args
            + ["--upgrade", "pip", "setuptools", "wheel"],
            env=env,
        )

    # Install project requirements with upgrade for latest versions
    run(
        pip_cmd
        + ["install"]
        + verbosity_flags
        + extra_install_args
        + ["--upgrade", "-r", requirements_file],
        env=env,
    )


if __name__ == "__main__":
    main()